    std::swap(TrueVal, FalseVal);

  auto FoldToBitwiseAnd = [&](Value *Remainder) -> Instruction * {
    Value *Add = Builder.CreateAdd(
        Remainder, Constant::getAllOnesValue(RemRes->getType()));
    return BinaryOperator::CreateAnd(Op, Add);
  };

  // Match the general case:
  // %rem = srem i32 %x, %n
  // %cnd = icmp slt i32 %rem, 0
  // %add = add i32 %rem, %n  --> or add %n, %rem (commutative)
  // %sel = select i1 %cnd, i32 %add, i32 %rem
  Value *Divisor = nullptr;
  Value *Amount = nullptr;
  if (match(TrueVal, m_c_Add(m_Specific(RemRes), m_Value(Divisor))) &&
      match(RemRes, m_SRem(m_Value(Op), m_Specific(Divisor))) &&
      match(Divisor, m_Shl(m_One(), m_Value(Amount))) &&
      FalseVal == RemRes) {
    // Divisor = 1 << Amount, so mask = (1 << Amount) - 1
    // We compute mask as: xor (shl nsw iN -1, Amount), -1
    Value *NegOne = Constant::getAllOnesValue(Divisor->getType());
    Value *Shifted = Builder.CreateNSWShl(NegOne, Amount);
    Value *Mask = Builder.CreateXor(Shifted, NegOne);
    return BinaryOperator::CreateAnd(Op, Mask);
  }

  // Match the case where the one arm has been replaced by constant 1:
  // %rem = srem i32 %n, 2
  // %cnd = icmp slt i32 %rem, 0
  // %sel = select i1 %cnd, i32 1, i32 %rem
  if (match(TrueVal, m_One()) &&
      match(RemRes, m_SRem(m_Value(Op), m_SpecificInt(2))) &&
      FalseVal == RemRes)
    return FoldToBitwiseAnd(ConstantInt::get(RemRes->getType(), 2));

  return nullptr;
